const input = $input.first().json;
const execution = input.execution || {};
const workflow = input.workflow || {};
const summary = {
  workflow_name: workflow.name || null,
  workflow_id: workflow.id || null,
  execution_id: execution.id || null,
  last_node: execution.lastNodeExecuted || null,
  message: execution.error?.message || input.message || 'Workflow execution failed',
  stack: execution.error?.stack || null,
  mode: execution.mode || null,
  failed_at: new Date().toISOString(),
};

return [
  {
    json: {
      execution_id: summary.execution_id,
      error_summary: summary,
    },
  },
];

const source = $("Build Error Payload").first().json;

return [
  {
    json: {
      ...source,
    },
  },
];

const input = $input.first().json;
const controlPlaneState = {
  ...(input.control_plane_state || {}),
  airtable: {
    ...(input.control_plane_state?.airtable || {}),
    enabled: String($env.AIRTABLE_CONTROL_PLANE_ENABLED || 'false').toLowerCase() === 'true',
    run_record_id: input.control_plane_state?.airtable?.run_record_id || null,
    last_action: input.control_plane_state?.airtable?.last_action || null,
    last_synced_at: input.control_plane_state?.airtable?.last_synced_at || null,
    last_error: input.control_plane_state?.airtable?.last_error || null,
    stage_attempt_syncs: input.control_plane_state?.airtable?.stage_attempt_syncs || 0,
    experiment_syncs: input.control_plane_state?.airtable?.experiment_syncs || 0,
    last_gate_record_id: input.control_plane_state?.airtable?.last_gate_record_id || null,
  },
};

return [
  {
    json: {
      ...input,
      control_plane_state: controlPlaneState,
      airtable_action: 'sync_failure_run',
    },
  },
];
